    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    2,
    'Full Body Fat Torch - 2w 4x/wk',
    'fat_loss',
    4,
    60,
    ARRAY['Maximize calorie burn', 'Preserve lean muscle']::text[],
